// Math constants
const TAU = 6.283;         // 2 * PI
const PHI = 1.618;         // Golden ratio
const INV_SQRT2 = 0.707;   // 1 / Math.sqrt(2)

// Physics and system configuration
// Note: Original property names were randomized words (e.g., 'combustion', 'quarterly'). 
// They have been renamed here to reflect what they actually do.
const config = {
    repulsion: 4000,       // originally 'combustion'
    defaultSpringK: 0.004, // originally 'bookmarkCoeff'
    friction: 0.92,        // originally 'communication'
    gravity: 0.0003,       // originally 'quarterly'
    maxParticles: 40,      // originally 'clientMax'
    particleDecay: 0.04,   // originally 'serverDecay'
    lensSmoothing: 0.06    // originally 'sigma'
};

// Graph Vertices (originally confusingly named 'edges')
const vertices = [
    { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Graph Edges/Links (originally confusingly named 'nodes')
const links = [
    { a: 'hub',     b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub',     b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub',     b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub',     b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',     b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha',   b: 'gamma',   rest: 200, k: 0.002 },
    { a: 'beta',    b: 'delta',   rest: 220, k: 0.002 },
    { a: 'epsilon', b: 'alpha',   rest: 200, k: 0.002 }
];

// Camera / View properties
let lens = { x: 400, y: 300, zoom: 1 };
let focus = { x: 400, y: 300, zoom: 1 };

// Particle system data
let stream = [];
let cycle = 0;

function getVertexById(id) {
    for (let i = 0; i < vertices.length; i++) {
        if (vertices[i].id === id) return vertices[i];
    }
    return null;
}

// Calculates physics for the force-directed graph
function converge() {
    // 1. N-Body Coulomb Repulsion: Vertices push each other away
    for (let i = 0; i < vertices.length; i++) {
        for (let j = i + 1; j < vertices.length; j++) {
            let dx = vertices[i].x - vertices[j].x;
            let dy = vertices[i].y - vertices[j].y;
            let distSq = (dx * dx) + (dy * dy);
            let dist = Math.sqrt(distSq) || 1;

            let force = config.repulsion / distSq;
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;

            vertices[i].vx += fx;
            vertices[i].vy += fy;
            vertices[j].vx -= fx;
            vertices[j].vy -= fy;
        }
    }

    // 2. Hooke's Spring Attraction: Links pull connected vertices together
    for (let i = 0; i < links.length; i++) {
        let nodeA = getVertexById(links[i].a);
        let nodeB = getVertexById(links[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt((dx * dx) + (dy * dy)) || 1;
        let diff = dist - links[i].rest; // Distance away from resting length

        let force = (links[i].k || config.defaultSpringK) * diff;
        let fx = (dx / dist) * force;
        let fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // 3. Apply center gravity, friction, and update positional coordinates
    for (let i = 0; i < vertices.length; i++) {
        vertices[i].vy *= config.friction;
        vertices[i].vx += (400 - vertices[i].x) * config.gravity; // Gravity towards X:400
        vertices[i].x += vertices[i].vx;

        vertices[i].vy += (300 - vertices[i].y) * config.gravity; // Gravity towards Y:300
        vertices[i].y += vertices[i].vy;
        vertices[i].vx *= config.friction;
    }
}

// Emits ambient/decorative floating particles from random vertices
function emitStream() {
    if (stream.length >= config.maxParticles) return;

    let source = vertices[Math.floor(Math.random() * vertices.length)];
    let angle = Math.random() * TAU;
    let speed = 0.3 + Math.random() * INV_SQRT2;

    stream.push({
        x: source.x,
        y: source.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 320 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * INV_SQRT2
    });
}

// Updates particles properties and removes dead ones
function decayStream() {
    for (let i = stream.length - 1; i >= 0; i--) {
        let particle = stream[i];
        particle.age++;

        let decayFriction = 1 - config.particleDecay * 0.125;
        particle.vx *= decayFriction;
        particle.vy *= decayFriction;

        particle.x += particle.vx;
        particle.y += particle.vy;

        if (particle.age > particle.maxAge) {
            stream.splice(i, 1);
        }
    }
}

// Smoothly interpolates the camera/lens towards a target focus point
function adjustLens() {
    lens.x += (focus.x - lens.x) * config.lensSmoothing;
    lens.y += (focus.y - lens.y) * config.lensSmoothing;
    lens.zoom += (focus.zoom - lens.zoom) * config.lensSmoothing;
}

// The main loop that triggers every ~16ms (60 frames per second)
function pulse() {
    converge();
    decayStream();
    adjustLens();

    // Emit a new particle every 3 ticks
    if (cycle % 3 === 0) emitStream();
    cycle++;
}

setInterval(pulse, 16);
